/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataSourceEventHandler(formDataSourceStr(PurchTable, PurchTable), FormDataSourceEventType::Activated)]
public static void PurchTable_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    InventParameters        InventParameters;
    PurchTable          PurchTable     = sender.cursor(); //selected record
    FormDataSource      PurchTable_ds   = sender.formRun().dataSource("PurchTable"); //DataSource
    FormRun             element       = sender.formRun(); //form element
    FormControl         QualityParameter   = element.design(0).controlName("QualityParameter"); //MenuitemName
    //button on the form

    select firstonly InventParameters;

    if(InventParameters.ETGEnableQualityParameter == NoYes::Yes)
    {
        QualityParameter.visible(true);
    }
    else
    {
        QualityParameter.visible(false);
    }

}
